content:
:root {
  color-scheme: dark;
  --xana-bg: #05070a;
  --xana-surface: #111827;
  --xana-surface-elevated: #151922;
  --xana-panel-bg: rgba(14, 18, 26, 0.96);
  --xana-panel-border: rgba(255, 255, 255, 0.08);
  --xana-text: #f8fafc;
  --xana-text-muted: #94a3b8;
  --xana-accent: #55d6be;
  --xana-accent-soft: rgba(85, 214, 190, 0.14);
  --xana-accent-border: rgba(85, 214, 190, 0.3);
  --xana-danger: #ff6b6b;
  --xana-ok: #91f2a6;
  --xana-yellow: #ffd166;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-width: 100%;
  min-height: 100%;
  overflow: hidden;
  background: var(--xana-bg);
  color: var(--xana-text);
  font-family: "IBM Plex Sans", "Segoe UI", system-ui, sans-serif;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  min-height: 34px;
  background: rgba(255, 255, 255, 0.06);
  color: var(--xana-text);
  border: 1px solid rgba(255, 255, 255, 0.14);
  padding: 0.48rem 0.72rem;
  border-radius: 0.65rem;
  cursor: pointer;
  transition: background 150ms ease, border-color 150ms ease, color 150ms ease;
}

button:hover:not(:disabled) {
  background: rgba(85, 214, 190, 0.13);
  border-color: rgba(85, 214, 190, 0.5);
  color: var(--xana-accent);
}

button:disabled {
  opacity: 0.42;
  cursor: not-allowed;
}

button.primary,
.primary {
  background: rgba(85, 214, 190, 0.16);
  border-color: rgba(85, 214, 190, 0.48);
  color: #b8fff0;
  font-weight: 850;
}

button.danger,
.danger {
  border-color: rgba(248, 113, 113, 0.5);
  color: #fecaca;
}

input,
textarea,
select {
  width: 100%;
  background: rgba(5, 7, 10, 0.9);
  color: var(--xana-text);
  border: 1px solid rgba(255, 255, 255, 0.14);
  border-radius: 0.72rem;
  padding: 0.56rem 0.68rem;
  outline: none;
}

input:focus,
textarea:focus,
select:focus {
  border-color: var(--xana-accent);
  box-shadow: 0 0 0 3px rgba(85, 214, 190, 0.12);
}

textarea {
  resize: vertical;
  line-height: 1.45;
}

label {
  display: block;
  color: var(--xana-text-muted);
  font-size: 0.72rem;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin: 1rem 0 0.4rem;
}

.field-label {
  display: flex;
  align-items: center;
  gap: 0.38rem;
}

.checkbox-row {
  display: flex;
  align-items: flex-start;
  gap: 0.75rem;
  margin: 0.7rem 0 0;
  padding: 0.75rem;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 0.85rem;
  background: rgba(255, 255, 255, 0.03);
  text-transform: none;
  letter-spacing: 0;
  color: var(--xana-text);
}

.checkbox-row input[type="checkbox"] {
  width: 18px;
  height: 18px;
  margin: 0.1rem 0 0;
  accent-color: var(--xana-accent);
  flex: 0 0 auto;
}

.checkbox-row span {
  display: flex;
  flex-direction: column;
  gap: 0.18rem;
}

.checkbox-row strong {
  font-size: 0.88rem;
}

.checkbox-row small {
  color: var(--xana-text-muted);
  font-size: 0.76rem;
  line-height: 1.4;
}

.help-hint {
  position: relative;
  display: inline-block;
  border: 0;
  padding: 0;
}

.help-hint summary {
  display: grid;
  place-items: center;
  width: 18px;
  height: 18px;
  border: 1px solid rgba(85, 214, 190, 0.42);
  border-radius: 999px;
  color: var(--xana-accent);
  background: rgba(85, 214, 190, 0.08);
  font-size: 0.68rem;
  line-height: 1;
  list-style: none;
}

.help-hint summary::-webkit-details-marker {
  display: none;
}

.help-popover {
  position: fixed;
  right: 1rem;
  top: 4.5rem;
  z-index: 200;
  width: min(320px, calc(100vw - 2rem));
  padding: 0.75rem;
  border: 1px solid var(--xana-accent-border);
  border-radius: 0.75rem;
  background: rgba(5, 7, 10, 0.98);
  box-shadow: 0 20px 55px rgba(0, 0, 0, 0.48);
  color: #cbd5e1;
  text-transform: none;
  letter-spacing: 0;
  font-size: 0.82rem;
  line-height: 1.45;
}

.help-popover p {
  margin: 0.4rem 0 0.6rem;
}

.help-popover a {
  color: var(--xana-accent);
  font-weight: 850;
}

pre {
  white-space: pre-wrap;
  word-break: break-word;
}

*::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

*::-webkit-scrollbar-track {
  background: rgba(10, 14, 19, 0.9);
}

*::-webkit-scrollbar-thumb {
  background: var(--xana-accent);
  border-radius: 999px;
  border: 2px solid rgba(10, 14, 19, 0.9);
}

.app-shell {
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: var(--xana-bg);
}

.topbar {
  position: relative;
  z-index: 1000;
  height: 52px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0 1.1rem;
  background: rgba(5, 7, 10, 0.96);
  border-bottom: 1px solid rgba(255, 255, 255, 0.07);
  backdrop-filter: blur(16px);
  flex-shrink: 0;
}

.brand {
  display: flex;
  gap: 0.55rem;
  align-items: center;
  min-width: 0;
}

.logo-mark {
  width: 30px;
  height: 30px;
  border-radius: 7px;
  object-fit: contain;
  background: #05070a;
  border: 1px solid rgba(255, 255, 255, 0.18);
  padding: 3px;
}

.brand-title {
  font-size: 0.86rem;
  font-weight: 950;
  letter-spacing: 0.03em;
}

.brand-subtitle {
  color: var(--xana-accent);
  font-size: 0.58rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  opacity: 0.85;
}

.brand-build {
  color: var(--xana-text-muted);
  font-size: 0.56rem;
  font-weight: 700;
  line-height: 1.25;
}

.top-actions {
  display: flex;
  gap: 0.42rem;
  align-items: center;
  overflow: visible;
}

.topbar-menu {
  position: relative;
  border: 0;
  padding: 0;
  overflow: visible;
}

.topbar-menu summary {
  min-height: 34px;
  padding: 0.48rem 0.9rem;
  border-radius: 0.65rem;
  border: 1px solid rgba(255, 255, 255, 0.14);
  background: rgba(255, 255, 255, 0.06);
  color: var(--xana-text);
  text-transform: none;
  letter-spacing: 0;
  font-size: 0.92rem;
}

.topbar-menu summary::-webkit-details-marker {
  display: none;
}

.topbar-menu[open] summary {
  background: rgba(85, 214, 190, 0.13);
  border-color: rgba(85, 214, 190, 0.45);
  color: var(--xana-accent);
}

.topbar-menu-panel {
  position: absolute;
  top: calc(100% + 0.45rem);
  right: 0;
  z-index: 1100;
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
  min-width: 220px;
  padding: 0.7rem;
  border: 1px solid var(--xana-panel-border);
  border-radius: 0.85rem;
  background: rgba(8, 12, 18, 0.98);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.45);
}

.topbar-menu-panel select,
.topbar-menu-panel button {
  width: 100%;
}

.notice {
  position: absolute;
  top: 62px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 120;
  max-width: min(780px, calc(100vw - 2rem));
  padding: 0.55rem 1rem;
  border-radius: 999px;
  border: 1px solid var(--xana-panel-border);
  background: rgba(5, 7, 10, 0.94);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.45);
}

.notice.success {
  color: var(--xana-ok);
}

.notice.error {
  color: var(--xana-danger);
}

.workspace-grid {
  flex: 1;
  min-height: 0;
  display: grid;
  grid-template-columns: 320px minmax(520px, 1fr) 410px;
}

.left-panel,
.right-panel {
  overflow: auto;
  background: var(--xana-panel-bg);
  padding: 0.75rem;
  min-width: 260px;
  max-width: 55vw;
}

.left-panel {
  border-right: 1px solid var(--xana-panel-border);
  resize: horizontal;
}

.right-panel {
  border-left: 1px solid var(--xana-panel-border);
  resize: horizontal;
}

.center-panel {
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: var(--xana-bg);
}

.panel-card {
  background: rgba(255, 255, 255, 0.035);
  border: 1px solid var(--xana-panel-border);
  border-radius: 0.85rem;
  padding: 0.85rem;
  margin-bottom: 0.75rem;
  min-height: 0;
}

.panel-card pre {
  max-height: 420px;
  overflow: auto;
  padding-right: 0.25rem;
}

.panel-title {
  font-size: 0.76rem;
  font-weight: 950;
  text-transform: uppercase;
  letter-spacing: 0.09em;
  color: var(--xana-text);
  margin-bottom: 0.45rem;
}

.panel-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.65rem;
}

.small {
  font-size: 0.78rem;
}

.muted {
  color: var(--xana-text-muted);
}

.manifest-name {
  font-weight: 900;
  font-size: 1.02rem;
  margin: 0.65rem 0;
}

.canon-warning,
.working-copy-warning {
  margin: 0.55rem 0;
  padding: 0.58rem 0.65rem;
  border: 1px solid rgba(255, 209, 102, 0.35);
  border-radius: 0.7rem;
  color: #ffe2a3;
  background: rgba(255, 209, 102, 0.08);
  font-size: 0.8rem;
  line-height: 1.45;
}

.working-copy-warning {
  border-color: rgba(85, 214, 190, 0.32);
  color: #b8fff0;
  background: rgba(85, 214, 190, 0.08);
}

.pill-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.pill {
  background: rgba(85, 214, 190, 0.1);
  border: 1px solid rgba(85, 214, 190, 0.24);
  border-radius: 999px;
  padding: 0.22rem 0.5rem;
  color: #b8fff0;
  font-size: 0.72rem;
  font-weight: 800;
}

.wide {
  width: 100%;
  margin: 0.35rem 0;
}

.catalog-list {
  margin-top: 0.75rem;
}

details {
  border-top: 1px solid var(--xana-panel-border);
  padding: 0.5rem 0;
}

summary {
  cursor: pointer;
  color: var(--xana-text-muted);
  font-weight: 850;
  display: flex;
  justify-content: space-between;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-size: 0.72rem;
}

.catalog-item {
  width: 100%;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 0.16rem;
  margin: 0.3rem 0;
  background: transparent;
}

.catalog-item.selected {
  border-color: var(--xana-accent);
  background: var(--xana-accent-soft);
}

.catalog-item small {
  color: var(--xana-accent);
  font-size: 0.68rem;
  font-weight: 850;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.center-tabs {
  min-height: 48px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.35rem;
  padding: 0 0.75rem;
  border-bottom: 1px solid var(--xana-panel-border);
  background: rgba(5, 7, 10, 0.84);
  flex-wrap: wrap;
}

.tab-group {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.center-tabs button.active {
  border-color: var(--xana-accent);
  color: var(--xana-accent);
  background: rgba(85, 214, 190, 0.13);
}

.projection-toolbar-title {
  color: var(--xana-text-muted);
  font-size: 0.82rem;
  font-weight: 800;
}

.graph-wrap {
  flex: 1;
  min-height: 0;
  padding: 1rem;
  position: relative;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background:
    radial-gradient(circle at 18% 22%, rgba(85, 214, 190, 0.14), transparent 30%),
    radial-gradient(circle at 82% 78%, rgba(251, 133, 0, 0.12), transparent 28%),
    linear-gradient(180deg, rgba(5, 7, 10, 0.96), rgba(5, 7, 10, 0.88));
}

.graph-wrap::before {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  opacity: 0.34;
  background-image:
    radial-gradient(circle at 12% 18%, rgba(255, 255, 255, 0.75) 0 1px, transparent 1.5px),
    radial-gradient(circle at 26% 72%, rgba(255, 255, 255, 0.55) 0 1px, transparent 1.5px),
    radial-gradient(circle at 44% 30%, rgba(255, 255, 255, 0.7) 0 1px, transparent 1.5px),
    radial-gradient(circle at 62% 62%, rgba(255, 255, 255, 0.5) 0 1px, transparent 1.5px),
    radial-gradient(circle at 78% 20%, rgba(255, 255, 255, 0.7) 0 1px, transparent 1.5px),
    radial-gradient(circle at 88% 52%, rgba(255, 255, 255, 0.5) 0 1px, transparent 1.5px);
}

.graph-search-shell {
  position: absolute;
  top: 1.1rem;
  left: 50%;
  z-index: 4;
  width: min(28rem, calc(100% - 10rem));
  transform: translateX(-50%);
}

.graph-search-input {
  width: 100%;
  min-height: 3rem;
  padding: 0.8rem 2.8rem 0.8rem 1rem;
  border-radius: 1.3rem;
  border-color: rgba(85, 214, 190, 0.24);
  background: rgba(5, 7, 10, 0.88);
  color: #b8fff0;
  font-size: 0.95rem;
  box-shadow: 0 18px 36px rgba(0, 0, 0, 0.35);
}

.graph-search-clear {
  position: absolute;
  top: 0.42rem;
  right: 0.45rem;
  min-width: 2rem;
  min-height: 2rem;
  padding: 0;
  border-radius: 999px;
}

.graph-search-results {
  margin-top: 0.45rem;
  padding: 0.55rem;
  border: 1px solid var(--xana-panel-border);
  border-radius: 0.95rem;
  background: rgba(8, 12, 18, 0.98);
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.42);
  max-height: min(22rem, 46vh);
  overflow: auto;
}

.graph-search-results ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

.graph-search-meta {
  margin-bottom: 0.45rem;
  color: var(--xana-text-muted);
  font-size: 0.76rem;
  font-weight: 800;
}

.graph-search-result {
  width: 100%;
  margin: 0.25rem 0;
  text-align: left;
  display: flex;
  flex-direction: column;
  gap: 0.16rem;
}

.graph-search-result-title {
  font-weight: 900;
}

.graph-search-result-meta,
.graph-search-result-snippet {
  color: var(--xana-text-muted);
  font-size: 0.78rem;
  line-height: 1.35;
}

.projection-split {
  flex: 1;
  min-height: 0;
  display: grid;
}

.projection-split .graph-wrap {
  border-right: 1px solid var(--xana-panel-border);
}

.split-control {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin: 0;
  text-transform: none;
  letter-spacing: 0;
  color: var(--xana-text-muted);
  font-size: 0.78rem;
  min-width: 190px;
}

.split-control input {
  padding: 0;
}

.link-mode-banner {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: #b8fff0;
  font-size: 0.8rem;
  font-weight: 850;
}

.link-mode-banner button {
  min-height: 28px;
  padding: 0.24rem 0.5rem;
}

.graph-instruction {
  position: absolute;
  top: 1.65rem;
  left: 50%;
  transform: translateX(-50%);
  z-index: 2;
  max-width: calc(100% - 3rem);
  padding: 0.42rem 0.7rem;
  border: 1px solid rgba(85, 214, 190, 0.45);
  border-radius: 999px;
  background: rgba(5, 7, 10, 0.88);
  color: #b8fff0;
  font-size: 0.78rem;
  font-weight: 850;
  pointer-events: none;
}

.graph-wrap.linking .graph-node circle {
  stroke: rgba(85, 214, 190, 0.62);
}

.graph-svg {
  width: 100%;
  flex: 1;
  min-height: 0;
  border: 1px solid var(--xana-panel-border);
  border-radius: 8px;
  background: rgba(5, 7, 10, 0.46);
  cursor: grab;
  touch-action: none;
  user-select: none;
}

.graph-wrap.panning .graph-svg {
  cursor: grabbing;
}

.graph-pan-surface {
  fill: transparent;
}

.graph-layer {
  transform-origin: 0 0;
}

.graph-tools,
.graph-depth-tools {
  position: absolute;
  z-index: 3;
  display: flex;
  gap: 0.32rem;
  padding: 0.34rem;
  border: 1px solid rgba(85, 214, 190, 0.24);
  border-radius: 999px;
  background: rgba(5, 7, 10, 0.82);
  box-shadow: 0 12px 28px rgba(0, 0, 0, 0.3);
  backdrop-filter: blur(14px);
}

.graph-tools {
  left: 1.65rem;
  bottom: 1.65rem;
}

.graph-depth-tools {
  top: 5rem;
  left: 50%;
  transform: translateX(-50%);
  min-width: min(25rem, calc(100% - 14rem));
  justify-content: center;
}

.graph-tools button,
.graph-depth-tools button {
  min-height: 2rem;
  min-width: 2rem;
  padding: 0 0.58rem;
  border-radius: 999px;
  border-color: rgba(148, 163, 184, 0.28);
  background: rgba(15, 19, 27, 0.92);
  font-size: 0.76rem;
  font-weight: 800;
}

.graph-tools button:hover,
.graph-depth-tools button:hover,
.graph-depth-tools button.active {
  border-color: var(--xana-accent);
  color: var(--xana-accent);
}

.graph-depth-tools button {
  flex: 1 1 0;
  min-width: 4.5rem;
  max-width: 6rem;
  color: #9fb1c7;
  font-size: 0.68rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.graph-depth-tools button.active {
  background: rgba(85, 214, 190, 0.18);
}

.graph-tools button.active {
  border-color: var(--xana-accent);
  color: var(--xana-accent);
  background: rgba(85, 214, 190, 0.16);
}

.graph-tour-settings {
  position: absolute;
  bottom: 5.2rem;
  left: 1rem;
  z-index: 4;
  width: min(24rem, calc(100% - 2rem));
}

.graph-tools-popover {
  position: absolute;
  bottom: 5.2rem;
  left: 1rem;
  z-index: 4;
  width: min(20rem, calc(100% - 2rem));
}

.graph-tools-popover-card {
  display: grid;
  gap: 0.75rem;
  padding: 0.95rem;
  border: 1px solid var(--xana-accent-border);
  border-radius: 0.95rem;
  background: rgba(8, 12, 18, 0.98);
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.42);
}

.graph-tools-popover-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
}

.graph-trail-player {
  position: absolute;
  left: 1rem;
  right: 1rem;
  bottom: 5.2rem;
  z-index: 4;
  display: grid;
  gap: 0.75rem;
  padding: 0.95rem;
  border: 1px solid var(--xana-accent-border);
  border-radius: 0.95rem;
  background: rgba(8, 12, 18, 0.98);
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.42);
}

.graph-trail-player-head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 0.75rem;
}

.graph-trail-player-title {
  display: grid;
  gap: 0.15rem;
}

.graph-trail-player-title span {
  color: var(--xana-accent);
  font-size: 0.68rem;
  font-weight: 950;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.graph-trail-player-title strong {
  color: #f8fafc;
  font-size: 1rem;
}

.graph-trail-player-title em {
  color: var(--xana-text-muted);
  font-style: normal;
  font-size: 0.82rem;
}

.graph-trail-player-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
}

.graph-trail-player-actions button {
  min-height: 2rem;
  min-width: 2rem;
  padding: 0 0.7rem;
  border-radius: 999px;
  border-color: rgba(148, 163, 184, 0.28);
  background: rgba(15, 19, 27, 0.92);
}

.graph-trail-player-actions button:hover:not(:disabled) {
  border-color: var(--xana-accent);
  color: var(--xana-accent);
}

.graph-trail-player-actions button:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.graph-trail-player-items {
  display: grid;
  gap: 0.45rem;
  max-height: 12rem;
  overflow: auto;
}

.graph-trail-player-item {
  width: 100%;
  display: grid;
  grid-template-columns: 2rem minmax(0, 1fr) auto;
  align-items: center;
  gap: 0.7rem;
  text-align: left;
  padding: 0.6rem 0.75rem;
