.edge {
  fill: none;
  stroke-linecap: round;
  stroke-linejoin: round;
  opacity: 0.9;
  pointer-events: none;
}

.edge-arrow {
  pointer-events: none;
  opacity: 0.95;
}

.edge-label {
  fill: #e2e8f0;
  font-family: "IBM Plex Sans", "Segoe UI", sans-serif;
  paint-order: stroke;
  stroke: rgba(5, 7, 10, 0.92);
  stroke-width: 4.5px;
  font-size: 12px;
  font-weight: 700;
  text-anchor: middle;
  pointer-events: auto;
  cursor: context-menu;
}

.graph-travel-layer {
  pointer-events: none;
}

.graph-travel-rail {
  stroke: rgba(85, 214, 190, 0.94);
  stroke-width: 4;
  stroke-linecap: round;
  stroke-dasharray: 10 8;
  filter: drop-shadow(0 0 10px rgba(85, 214, 190, 0.38));
  opacity: 0;
  animation: graph-travel-rail 620ms ease-out var(--travel-delay, 0ms) forwards;
}

.graph-travel-start {
  fill: rgba(255, 255, 255, 0.95);
  stroke: rgba(85, 214, 190, 0.95);
  stroke-width: 2;
}

.graph-travel-step {
  fill: rgba(85, 214, 190, 0.95);
  stroke: rgba(255, 255, 255, 0.9);
  stroke-width: 2;
  opacity: 0;
  transform-box: fill-box;
  transform-origin: center;
  animation: graph-travel-step 360ms ease-out var(--travel-delay, 0ms) forwards;
}

@keyframes graph-travel-rail {
  from {
    stroke-dashoffset: 112;
    opacity: 0;
  }
  to {
    stroke-dashoffset: 0;
    opacity: 0.96;
  }
}

@keyframes graph-travel-step {
  from {
    transform: scale(0.58);
    opacity: 0;
  }
  to {
    transform: scale(1);
    opacity: 0.96;
  }
}

