  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 0.8rem;
  background: rgba(5, 7, 10, 0.5);
}

.custom-property-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
}

.custom-property-head strong {
  font-size: 0.84rem;
  color: var(--xana-text);
  word-break: break-word;
}

.mounted-review-stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(148px, 1fr));
  gap: 0.65rem;
  margin: 0.6rem 0 0.75rem;
}

.mounted-review-stat {
  padding: 0.65rem 0.75rem;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 0.8rem;
  background: rgba(255, 255, 255, 0.04);
}

.mounted-review-stat strong {
  display: block;
  font-size: 1rem;
  color: var(--xana-text);
}

.mounted-review-stat small {
  display: block;
  margin-top: 0.18rem;
  color: var(--xana-text-muted);
  line-height: 1.35;
}

.relationship-catalog {
  display: grid;
  gap: 0.65rem;
}

.relationship-filters,
.relationship-form {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.4rem;
}

.relationship-form {
  grid-template-columns: minmax(0, 1fr) auto;
  margin-top: 0.5rem;
}

.graph-node-menu {
  position: fixed;
  z-index: 40;
  width: min(300px, calc(100vw - 2rem));
  padding: 0.8rem;
  border: 1px solid var(--xana-accent-border);
  border-radius: 0.9rem;
  background: rgba(5, 7, 10, 0.98);
  box-shadow: 0 20px 55px rgba(0, 0, 0, 0.48);
  display: grid;
  gap: 0.7rem;
}

.graph-node-menu-title {
  font-size: 0.92rem;
  font-weight: 900;
  color: var(--xana-text);
  line-height: 1.35;
}

.graph-node-menu-field {
  margin: 0;
  display: grid;
  gap: 0.35rem;
  color: var(--xana-text-muted);
  font-size: 0.72rem;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.graph-node-menu-actions {
  display: grid;
  gap: 0.4rem;
}

.relationship-type-list {
  max-height: 180px;
  overflow: auto;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(145px, 1fr));
  gap: 0.35rem;
  padding-right: 0.2rem;
}

.relationship-type-option {
  text-align: left;
  min-height: 58px;
  display: flex;
  flex-direction: column;
  align-items: start;
  justify-content: center;
  gap: 0.12rem;
}

.relationship-type-option.selected {
  border-color: var(--xana-accent);
  background: rgba(85, 214, 190, 0.14);
}

.relationship-type-option small {
  color: var(--xana-text-muted);
  font-size: 0.68rem;
}

.relationship-chip,
.suggestion,
.issue {
  border: 1px solid var(--xana-panel-border);
  background: rgba(255, 255, 255, 0.04);
  border-radius: 0.65rem;
}

.relationship-chip {
  padding: 0.45rem 0.55rem;
  margin: 0.35rem 0;
  color: #cbd5e1;
}

.relationship-definition,
.trail-sequence-list {
  display: grid;
  gap: 0.55rem;
}

.relationship-chip-main,
.relationship-chip-actions {
  display: flex;
  align-items: center;
  gap: 0.55rem;
  flex-wrap: wrap;
}

.relationship-chip-main select {
  flex: 1 1 220px;
  min-width: 0;
}

.relationship-chip-actions {
  margin-top: 0.45rem;
}

.relationship-chip-actions button {
  padding: 0.45rem 0.65rem;
  min-height: 0;
}

.mounted-node-row {
  display: grid;
  gap: 0.35rem;
  margin-top: 0.4rem;
}

.mounted-node-row .checkbox-row {
  margin: 0;
}

.relationship-chip-actions .danger {
  border-color: rgba(248, 113, 113, 0.55);
  color: #fecaca;
}

.relationship-chip small {
  display: block;
  margin-top: 0.25rem;
  color: var(--xana-text-muted);
}

.trail-sequence-list {
  display: grid;
  gap: 0.35rem;
  margin-top: 0.65rem;
}

.relationship-definition {
  margin-top: 0.55rem;
  padding: 0.65rem;
  border: 1px solid var(--xana-panel-border);
  border-radius: 8px;
  color: #cbd5e1;
  background: rgba(255, 255, 255, 0.035);
  font-size: 0.82rem;
}

.relationship-definition p {
  margin: 0.5rem 0 0;
  line-height: 1.45;
}

.relationship-actions {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.55rem;
  margin-top: 0.55rem;
}

.relationship-actions a {
  color: var(--xana-accent);
  font-weight: 850;
  font-size: 0.78rem;
}

.suggestion {
  width: 100%;
  text-align: left;
  margin: 0.3rem 0;
}

.health-view {
  padding: 1rem;
  overflow: auto;
}

.score-card {
  background: rgba(255, 255, 255, 0.035);
  border: 1px solid var(--xana-panel-border);
  border-radius: 1rem;
  padding: 1.2rem;
  margin-bottom: 1rem;
  display: flex;
  align-items: baseline;
  gap: 1rem;
}

.score {
  font-size: 3rem;
  font-weight: 950;
  color: var(--xana-accent);
}

.health-columns {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
}

.issue {
  padding: 0.5rem;
  margin: 0.35rem 0;
  color: #cbd5e1;
}

.mounted-node-list {
  display: grid;
  gap: 0.3rem;
  max-height: 320px;
  overflow: auto;
  margin-top: 0.6rem;
  padding-right: 0.2rem;
}

.log-view {
  margin: 0;
  padding: 1rem;
  overflow: auto;
  height: 100%;
  background: #05070a;
  color: #cbd5e1;
}

@media (max-width: 1200px) {
  .workspace-grid {
    grid-template-columns: 280px 1fr 360px;
  }
}

@media (max-width: 980px) {
  html,
  body {
    overflow: auto;
  }

  .app-shell {
    min-height: 100vh;
    height: auto;
  }

  .topbar {
    height: auto;
    min-height: 52px;
    flex-wrap: wrap;
    padding: 0.65rem 0.75rem;
  }

  .workspace-grid {
    grid-template-columns: 1fr;
  }

  .left-panel,
  .right-panel {
    border: 0;
    border-bottom: 1px solid var(--xana-panel-border);
  }

  .center-panel {
    min-height: 560px;
  }

  .graph-wrap {
    min-height: 520px;
  }

  .health-columns,
  .relationship-form {
    grid-template-columns: 1fr;
  }
}
